public int compare(Node[] n1, Node[] n2) {
		if(n1==n2){
			return 0;
		}

		int min = Math.min(Math.min(n1.length, n2.length),_n);
		for (int i=0; i<min; i++) {
			if(_order!=null){
				if(_order.length==i){
					if(_nZero)
						return NOT_EQUALS_COMP;
					return 0;
				}

				int index = _order[i];
				if(index>=n1.length || index>=n2.length){
					_log.warning("Cannot compare "+Nodes.toString(n1)+" with "+Nodes.toString(n2)+" for order "+_order);
					return Integer.MIN_VALUE;
				}else{
					int comp = compare(n1[index], n2[index], _numeric!=null && _numeric.length>index && _numeric[index], _reverse!=null && _reverse.length>index && _reverse[index] );
					if (comp != 0)
						return comp;
				}
			}else{
				int comp = n1[i].compareTo(n2[i]);
				if (comp != 0)
					return comp;
			}
		}

		if(!_variableLength){
			int dif = n1.length - n2.length;
			if(dif!=0){
				return dif;
			}
		}

		if(_nZero)
			return NOT_EQUALS_COMP;;
		return 0;
	}

