      machine.backtrack();
      return;
    }
    Token previousToken = machine.tokenAt(-1);
    Token nextToken = machine.tokenAt(0);
    if (nextToken.getColumn() <= previousToken.getColumn() + previousToken.getValue().length()
        && nextToken.getLine() == previousToken.getLine()) {
      machine.jump(1);
    } else {
      machine.backtrack();
    }
  }

