public final int pop() {
    if (bufferPosition >= buffer.length) {
      return -1;
    }
    int character = buffer[bufferPosition];
    bufferPosition++;
    updateCursorPosition(character);
    if (recordingMode) {
      recordedCharacters.append((char) character);
    }
    lastChar = character;
    return character;
  }

