        compareCalendarWithExpectedValues(calendar, 2015, 12, 24, 20, 1, 0);

        // test for pattern: "yyyy-MM-dd'T'HH:mm:ss"
        calendar = adapter.unmarshal("2018-02-03T10:00:02");
