    public void shouldReturnAnAdId() throws InterruptedException {
        CountDownLatch latch = new CountDownLatch(1);
        AdIdRequestTask.AdIdCallback adIdCallback = result -> {
            assertNotNull(result);
            assertNotNull(result.getAdId());
            latch.countDown();
