        Robolectric.getBackgroundThreadScheduler().unPause();
        AdIdRequestTask adIdRequestTask = new AdIdRequestTask(ApplicationProvider.getApplicationContext(), adIdCallback);
        adIdRequestTask.execute();
        latch.await();
    }

